#!/usr/bin/env python3\n\"\"\"\nData Logging System for Portable Solar Power Generator\nMS Engineering College Final Year Project\n\"\"\"\n\nimport json\nimport csv\nimport os\nfrom datetime import datetime, timedelta\nfrom typing import List, Dict, Any\nimport matplotlib.pyplot as plt\nimport numpy as np\n\nclass DataLogger:\n    \"\"\"Data logging and analysis for solar power generator\"\"\"\n    \n    def __init__(self, log_dir: str = \"data\"):\n        self.log_dir = log_dir\n        self.json_log_file = os.path.join(log_dir, \"system_log.json\")\n        self.csv_log_file = os.path.join(log_dir, \"daily_summary.csv\")\n        \n        # Create directories if they don't exist\n        os.makedirs(log_dir, exist_ok=True)\n        \n    def log_data_point(self, data: Dict[str, Any]) -> None:\n        \"\"\"Log a single data point to JSON file\"\"\"\n        try:\n            with open(self.json_log_file, 'a') as f:\n                f.write(json.dumps(data) + '\\n')\n        except Exception as e:\n            print(f\"Error logging data: {e}\")\n    \n    def read_log_data(self, hours: int = 24) -> List[Dict[str, Any]]:\n        \"\"\"Read log data from the last N hours\"\"\"\n        data_points = []\n        cutoff_time = datetime.now() - timedelta(hours=hours)\n        \n        try:\n            if os.path.exists(self.json_log_file):\n                with open(self.json_log_file, 'r') as f:\n                    for line in f:\n                        try:\n                            data = json.loads(line.strip())\n                            log_time = datetime.strptime(data['timestamp'], '%Y-%m-%d %H:%M:%S')\n                            if log_time >= cutoff_time:\n                                data_points.append(data)\n                        except (json.JSONDecodeError, KeyError, ValueError):\n                            continue\n        except Exception as e:\n            print(f\"Error reading log data: {e}\")\n            \n        return data_points\n    \n    def generate_daily_summary(self) -> Dict[str, Any]:\n        \"\"\"Generate daily performance summary\"\"\"\n        data_points = self.read_log_data(24)\n        \n        if not data_points:\n            return {}\n            \n        # Calculate statistics\n        battery_levels = [d['battery_level'] for d in data_points]\n        solar_voltages = [d['solar_voltage'] for d in data_points]\n        energy_generated = [d.get('energy_generated', 0) for d in data_points]\n        energy_consumed = [d.get('energy_consumed', 0) for d in data_points]\n        \n        summary = {\n            'date': datetime.now().strftime('%Y-%m-%d'),\n            'avg_battery_level': round(np.mean(battery_levels), 1),\n            'min_battery_level': round(min(battery_levels), 1),\n            'max_battery_level': round(max(battery_levels), 1),\n            'avg_solar_voltage': round(np.mean(solar_voltages), 1),\n            'max_solar_voltage': round(max(solar_voltages), 1),\n            'total_energy_generated': round(max(energy_generated), 2),\n            'total_energy_consumed': round(max(energy_consumed), 2),\n            'charging_hours': sum(1 for d in data_points if d.get('is_charging', False)),\n            'data_points': len(data_points)\n        }\n        \n        return summary\n    \n    def save_daily_summary(self) -> None:\n        \"\"\"Save daily summary to CSV file\"\"\"\n        summary = self.generate_daily_summary()\n        \n        if not summary:\n            return\n            \n        # Check if CSV file exists, create header if not\n        file_exists = os.path.exists(self.csv_log_file)\n        \n        try:\n            with open(self.csv_log_file, 'a', newline='') as f:\n                writer = csv.DictWriter(f, fieldnames=summary.keys())\n                \n                if not file_exists:\n                    writer.writeheader()\n                    \n                writer.writerow(summary)\n                \n        except Exception as e:\n            print(f\"Error saving daily summary: {e}\")\n    \n    def plot_battery_performance(self, hours: int = 24) -> None:\n        \"\"\"Plot battery performance over time\"\"\"\n        data_points = self.read_log_data(hours)\n        \n        if not data_points:\n            print(\"No data available for plotting\")\n            return\n            \n        # Extract data for plotting\n        timestamps = [datetime.strptime(d['timestamp'], '%Y-%m-%d %H:%M:%S') for d in data_points]\n        battery_levels = [d['battery_level'] for d in data_points]\n        solar_voltages = [d['solar_voltage'] for d in data_points]\n        charging_status = [d.get('is_charging', False) for d in data_points]\n        \n        # Create subplots\n        fig, (ax1, ax2, ax3) = plt.subplots(3, 1, figsize=(12, 10))\n        fig.suptitle('Solar Power Generator Performance', fontsize=16)\n        \n        # Battery level plot\n        ax1.plot(timestamps, battery_levels, 'b-', linewidth=2, label='Battery Level')\n        ax1.set_ylabel('Battery Level (%)')\n        ax1.set_title('Battery Level Over Time')\n        ax1.grid(True, alpha=0.3)\n        ax1.legend()\n        \n        # Solar voltage plot\n        ax2.plot(timestamps, solar_voltages, 'orange', linewidth=2, label='Solar Voltage')\n        ax2.set_ylabel('Solar Voltage (V)')\n        ax2.set_title('Solar Panel Voltage')\n        ax2.grid(True, alpha=0.3)\n        ax2.legend()\n        \n        # Charging status plot\n        charging_y = [1 if status else 0 for status in charging_status]\n        ax3.fill_between(timestamps, charging_y, alpha=0.6, color='green', label='Charging')\n        ax3.set_ylabel('Charging Status')\n        ax3.set_xlabel('Time')\n        ax3.set_title('Charging Status')\n        ax3.set_ylim(-0.1, 1.1)\n        ax3.set_yticks([0, 1])\n        ax3.set_yticklabels(['Not Charging', 'Charging'])\n        ax3.grid(True, alpha=0.3)\n        ax3.legend()\n        \n        # Format x-axis\n        for ax in [ax1, ax2, ax3]:\n            ax.tick_params(axis='x', rotation=45)\n            \n        plt.tight_layout()\n        \n        # Save plot\n        plot_file = os.path.join(self.log_dir, f\"performance_{datetime.now().strftime('%Y%m%d_%H%M')}.png\")\n        plt.savefig(plot_file, dpi=300, bbox_inches='tight')\n        plt.show()\n        \n        print(f\"Performance plot saved to: {plot_file}\")\n    \n    def generate_report(self) -> str:\n        \"\"\"Generate text report of system performance\"\"\"\n        summary = self.generate_daily_summary()\n        \n        if not summary:\n            return \"No data available for report generation.\"\n            \n        report = f\"\"\"\n=== SOLAR POWER GENERATOR DAILY REPORT ===\nDate: {summary['date']}\n\nBATTERY PERFORMANCE:\n• Average Level: {summary['avg_battery_level']}%\n• Minimum Level: {summary['min_battery_level']}%\n• Maximum Level: {summary['max_battery_level']}%\n\nSOLAR GENERATION:\n• Average Voltage: {summary['avg_solar_voltage']}V\n• Peak Voltage: {summary['max_solar_voltage']}V\n• Charging Hours: {summary['charging_hours']}\n\nENERGY STATISTICS:\n• Total Generated: {summary['total_energy_generated']} units\n• Total Consumed: {summary['total_energy_consumed']} units\n• Net Balance: {summary['total_energy_generated'] - summary['total_energy_consumed']:.2f} units\n\nSYSTEM STATUS:\n• Data Points Collected: {summary['data_points']}\n• System Uptime: {(summary['data_points'] / 1440 * 100):.1f}% (assuming 1-minute intervals)\n\n=== END OF REPORT ===\n        \"\"\"\n        \n        return report\n    \n    def cleanup_old_logs(self, days: int = 30) -> None:\n        \"\"\"Remove log entries older than specified days\"\"\"\n        cutoff_time = datetime.now() - timedelta(days=days)\n        temp_file = self.json_log_file + \".temp\"\n        \n        try:\n            with open(self.json_log_file, 'r') as infile, open(temp_file, 'w') as outfile:\n                for line in infile:\n                    try:\n                        data = json.loads(line.strip())\n                        log_time = datetime.strptime(data['timestamp'], '%Y-%m-%d %H:%M:%S')\n                        if log_time >= cutoff_time:\n                            outfile.write(line)\n                    except (json.JSONDecodeError, KeyError, ValueError):\n                        continue\n                        \n            # Replace original file with cleaned version\n            os.replace(temp_file, self.json_log_file)\n            print(f\"Cleaned up logs older than {days} days\")\n            \n        except Exception as e:\n            print(f\"Error cleaning up logs: {e}\")\n            if os.path.exists(temp_file):\n                os.remove(temp_file)\n\n# Example usage and testing\nif __name__ == \"__main__\":\n    logger = DataLogger()\n    \n    # Generate sample data for demonstration\n    print(\"Generating sample data...\")\n    for i in range(24):\n        sample_data = {\n            'timestamp': (datetime.now() - timedelta(hours=23-i)).strftime('%Y-%m-%d %H:%M:%S'),\n            'battery_level': 50 + 30 * np.sin(i * np.pi / 12),  # Simulate daily cycle\n            'solar_voltage': max(0, 15 + 3 * np.sin((i-6) * np.pi / 12)),  # Peak at noon\n            'is_charging': 6 <= i <= 18,  # Charging during day\n            'energy_generated': i * 0.5,\n            'energy_consumed': i * 0.3\n        }\n        logger.log_data_point(sample_data)\n    \n    # Generate and display report\n    print(\"\\n\" + logger.generate_report())\n    \n    # Save daily summary\n    logger.save_daily_summary()\n    print(\"\\nDaily summary saved to CSV\")\n    \n    # Generate performance plot\n    try:\n        logger.plot_battery_performance()\n    except ImportError:\n        print(\"Matplotlib not available - skipping plot generation\")\n    \n    print(\"\\nData logging demonstration complete!\")